# Function to check basic properties of a binary relation
# Relation represented as set of ordered pairs

def is_reflexive(relation, domain):
    """Check if relation is reflexive: ∀a∈A, (a,a)∈R"""
    for element in domain:
        if (element, element) not in relation:
            return False
    return True

def is_symmetric(relation):
    """Check if relation is symmetric: ∀(a,b)∈R, (b,a)∈R"""
    for (a, b) in relation:
        if (b, a) not in relation:
            return False
    return True

def is_antisymmetric(relation):
    """Check if relation is antisymmetric: (a,b)∈R and (b,a)∈R implies a=b"""
    for (a, b) in relation:
        if a != b and (b, a) in relation:
            return False
    return True

def is_transitive(relation):
    """Check if relation is transitive: (a,b)∈R and (b,c)∈R implies (a,c)∈R"""
    # Convert to list for easier iteration
    pairs = list(relation)
    for (a, b) in pairs:
        for (c, d) in pairs:
            if b == c and (a, d) not in relation:
                return False
    return True

# Example: Consider relation R on set A = {1,2,3,4}
# R = {(1,1), (2,2), (3,3), (4,4), (1,2), (2,3), (1,3)}
domain = {1, 2, 3, 4}
relation = {(1,1), (2,2), (3,3), (4,4), (1,2), (2,3), (1,3)}

print("Relation R:", relation)
print("Domain:", domain)
print("Is Reflexive?", is_reflexive(relation, domain))
print("Is Symmetric?", is_symmetric(relation))
print("Is Antisymmetric?", is_antisymmetric(relation))
print("Is Transitive?", is_transitive(relation))

# Check if relation is an equivalence relation and find equivalence classes

def is_equivalence_relation(relation, domain):
    """Check if relation is equivalence: reflexive + symmetric + transitive"""
    # Check reflexive
    for a in domain:
        if (a, a) not in relation:
            return False, "Not reflexive"

    # Check symmetric
    for (a, b) in relation:
        if (b, a) not in relation:
            return False, "Not symmetric"

    # Check transitive
    pairs = list(relation)
    for (a, b) in pairs:
        for (c, d) in pairs:
            if b == c and (a, d) not in relation:
                return False, "Not transitive"

    return True, "Is equivalence relation"

def find_equivalence_classes(relation, domain):
    """Find equivalence classes for each element in domain"""
    classes = {}
    for a in domain:
        # Find all elements related to 'a'
        related = {b for (x, b) in relation if x == a}
        related.add(a)  # Include self
        classes[a] = related
    return classes

# Example: Relation 'congruence mod 3' on set {0,1,2,3,4,5}
# R = {(a,b) | a ≡ b (mod 3)}
domain = {0, 1, 2, 3, 4, 5}
relation = set()

# Generate all pairs where a ≡ b (mod 3)
for a in domain:
    for b in domain:
        if (a - b) % 3 == 0:
            relation.add((a, b))

print("Relation: congruence mod 3")
print("Relation R:", sorted(relation))
is_equiv, msg = is_equivalence_relation(relation, domain)
print(msg)

if is_equiv:
    classes = find_equivalence_classes(relation, domain)
    print("\nEquivalence Classes:")
    for element, cls in sorted(classes.items()):
        print(f"  [{element}] = {cls}")

# Check partial order relation and find Hasse diagram components

def is_partial_order(relation, domain):
    """Check if relation is partial order: reflexive + antisymmetric + transitive"""
    # Check reflexive
    for a in domain:
        if (a, a) not in relation:
            return False, "Not reflexive"

    # Check antisymmetric
    for (a, b) in relation:
        if a != b and (b, a) in relation:
            return False, "Not antisymmetric"

    # Check transitive
    pairs = list(relation)
    for (a, b) in pairs:
        for (c, d) in pairs:
            if b == c and (a, d) not in relation:
                return False, "Not transitive"

    return True, "Is partial order (POSET)"

def find_cover_relation(relation, domain):
    """Find cover relation (immediate predecessors/successors)"""
    # (a,b) is a cover if a < b and no c exists such that a < c < b
    cover = set()
    for (a, b) in relation:
        if a != b:
            # Check if there's intermediate element
            has_intermediate = False
            for (c, d) in relation:
                if a != c and c != b and b != d:
                    if (a, c) in relation and (c, b) in relation:
                        has_intermediate = True
                        break
            if not has_intermediate:
                cover.add((a, b))
    return cover

def find_maximal_minimal(relation, domain):
    """Find maximal and minimal elements of poset"""
    # Element a is maximal if there's no b ≠ a such that a < b
    # Element a is minimal if there's no b ≠ a such that b < a

    maximal = []
    minimal = []

    for a in domain:
        is_maximal = True
        is_minimal = True

        for b in domain:
            if a != b:
                if (a, b) in relation:  # a < b exists
                    is_maximal = False
                if (b, a) in relation:  # b < a exists
                    is_minimal = False

        if is_maximal:
            maximal.append(a)
        if is_minimal:
            minimal.append(a)

    return maximal, minimal

# Example: Divisibility relation on {1,2,3,4,6,12}
# R = {(a,b) | a divides b}
domain = {1, 2, 3, 4, 6, 12}
relation = set()

for a in domain:
    for b in domain:
        if b % a == 0:
            relation.add((a, b))

print("Relation: divisibility on {1,2,3,4,6,12}")
is_po, msg = is_partial_order(relation, domain)
print(msg)

if is_po:
    cover = find_cover_relation(relation, domain)
    print("\nCover Relation (edges in Hasse diagram):")
    print(sorted(cover))

    maximal, minimal = find_maximal_minimal(relation, domain)
    print(f"\nMaximal elements: {maximal}")
    print(f"Minimal elements: {minimal}")
